solutions.python:
class Solution:
    def getProjectedQuery(self, fieldPath: str) -> dict:
        if fieldPath == '':
            return {}
        fields = fieldPath.split('.')
        projectedQuery = {}
        for f in fields:
            if f != '':
                projectedQuery[f] = 1
        return projectedQuery
